BEGIN; CREATE OR REPLACE FUNCTION public.sales_command_center_report_v2(p1_start date, p1_end date, p2_start date, p2_end date) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE v_result jsonb; var_kpis_json jsonb; v_customer_stats jsonb; v_product_stats jsonb; v_entity_stats jsonb; v_diagnostics jsonb; v_week_start date := p1_end - 6; v_prev_week_start date := p1_end - 13; v_prev_week_end date := p1_end - 7; v_min_date date; v_max_date date; v_zero uuid := '00000000-0000-0000-0000-000000000000'::uuid; BEGIN IF p1_start IS NULL OR p1_end IS NULL OR p2_start IS NULL OR p2_end IS NULL THEN RAISE EXCEPTION 'Thieu ngay bao cao Sales.'; END IF; IF p1_start > p1_end OR p2_start > p2_end THEN RAISE EXCEPTION 'Khoang ngay bao cao Sales khong hop le.'; END IF; v_min_date := LEAST(p1_start, p2_start, v_prev_week_start); v_max_date := GREATEST(p1_end, p2_end); WITH base_out AS ( SELECT t.id, t.tx_date::date AS report_date, t.product_id, t.customer_id, t.qty, t.unit_cost, t.shipment_id, t.product_name_snapshot, t.product_spec_snapshot FROM public.inventory_transactions t WHERE t.tx_type = 'out' AND t.deleted_at IS NULL AND t.tx_date::date >= v_min_date AND t.tx_date::date <= v_max_date ), eff_tx AS ( SELECT b.id, b.report_date, b.product_id, b.customer_id, b.shipment_id, b.qty AS eff_qty, COALESCE(b.unit_cost, p.unit_price) AS eff_price, (b.unit_cost IS NULL AND p.unit_price IS NULL) AS missing_price, b.product_name_snapshot, b.product_spec_snapshot FROM base_out b LEFT JOIN public.products p ON p.id = b.product_id UNION ALL SELECT a.id, b.report_date, b.product_id, b.customer_id, b.shipment_id, CASE WHEN a.tx_type = 'adjust_in' THEN a.qty ELSE -a.qty END AS eff_qty, COALESCE(a.unit_cost, b.unit_cost, p.unit_price) AS eff_price, (a.unit_cost IS NULL AND b.unit_cost IS NULL AND p.unit_price IS NULL) AS missing_price, COALESCE(a.product_name_snapshot, b.product_name_snapshot) AS product_name_snapshot, COALESCE(a.product_spec_snapshot, b.product_spec_snapshot) AS product_spec_snapshot FROM public.inventory_transactions a JOIN base_out b ON b.id = a.adjusted_from_transaction_id LEFT JOIN public.products p ON p.id = b.product_id WHERE a.tx_type IN ('adjust_in', 'adjust_out') AND a.deleted_at IS NULL ), calc_tx AS ( SELECT *, eff_qty * COALESCE(eff_price, 0) AS revenue FROM eff_tx ), p1_tx AS ( SELECT COALESCE(SUM(revenue), 0) AS rev, COALESCE(SUM(eff_qty), 0) AS qty, GREATEST(1, COUNT(DISTINCT report_date))::int AS active_days, COALESCE(COUNT(*) FILTER (WHERE missing_price), 0)::int AS missing_price_rows FROM calc_tx WHERE report_date >= p1_start AND report_date <= p1_end ), p2_tx AS ( SELECT COALESCE(SUM(revenue), 0) AS rev, COALESCE(SUM(eff_qty), 0) AS qty, GREATEST(1, COUNT(DISTINCT report_date))::int AS active_days, COALESCE(COUNT(*) FILTER (WHERE missing_price), 0)::int AS missing_price_rows FROM calc_tx WHERE report_date >= p2_start AND report_date <= p2_end ), p1_ship_tx AS ( SELECT COALESCE(SUM(revenue), 0) AS rev FROM calc_tx WHERE shipment_id IS NOT NULL AND report_date >= p1_start AND report_date <= p1_end ), p2_ship_tx AS ( SELECT COALESCE(SUM(revenue), 0) AS rev FROM calc_tx WHERE shipment_id IS NOT NULL AND report_date >= p2_start AND report_date <= p2_end ), p1_week_tx AS ( SELECT COALESCE(SUM(revenue), 0) AS rev, COALESCE(SUM(eff_qty), 0) AS qty, GREATEST(1, COUNT(DISTINCT report_date))::int AS active_days FROM calc_tx WHERE report_date >= v_week_start AND report_date <= p1_end ), p1_prev_week_tx AS ( SELECT COALESCE(SUM(revenue), 0) AS rev, COALESCE(SUM(eff_qty), 0) AS qty, GREATEST(1, COUNT(DISTINCT report_date))::int AS active_days FROM calc_tx WHERE report_date >= v_prev_week_start AND report_date <= v_prev_week_end ), p1_ship AS ( SELECT count(*)::int AS count FROM public.shipment_logs WHERE deleted_at IS NULL AND shipment_date >= p1_start AND shipment_date <= p1_end ), p2_ship AS ( SELECT count(*)::int AS count FROM public.shipment_logs WHERE deleted_at IS NULL AND shipment_date >= p2_start AND shipment_date <= p2_end ), p1_week_ship AS ( SELECT count(*)::int AS count FROM public.shipment_logs WHERE deleted_at IS NULL AND shipment_date >= v_week_start AND shipment_date <= p1_end ), p1_prev_week_ship AS ( SELECT count(*)::int AS count FROM public.shipment_logs WHERE deleted_at IS NULL AND shipment_date >= v_prev_week_start AND shipment_date <= v_prev_week_end ) SELECT jsonb_build_object('p1_revenue', (SELECT rev FROM p1_tx), 'p2_revenue', (SELECT rev FROM p2_tx), 'p1_shipment_revenue', (SELECT rev FROM p1_ship_tx), 'p2_shipment_revenue', (SELECT rev FROM p2_ship_tx), 'p1_qty', (SELECT qty FROM p1_tx), 'p2_qty', (SELECT qty FROM p2_tx), 'p1_shipments', (SELECT count FROM p1_ship), 'p2_shipments', (SELECT count FROM p2_ship), 'p1_days', (SELECT active_days FROM p1_tx), 'p2_days', (SELECT active_days FROM p2_tx), 'p1_week_revenue', (SELECT rev FROM p1_week_tx), 'p1_previous_week_revenue', (SELECT rev FROM p1_prev_week_tx), 'p1_week_qty', (SELECT qty FROM p1_week_tx), 'p1_previous_week_qty', (SELECT qty FROM p1_prev_week_tx), 'p1_week_days', (SELECT active_days FROM p1_week_tx), 'p1_previous_week_days', (SELECT active_days FROM p1_prev_week_tx), 'p1_week_shipments', (SELECT count FROM p1_week_ship), 'p1_previous_week_shipments', (SELECT count FROM p1_prev_week_ship), 'p1_missing_price_rows', (SELECT missing_price_rows FROM p1_tx), 'p2_missing_price_rows', (SELECT missing_price_rows FROM p2_tx)) INTO var_kpis_json; WITH base_out AS ( SELECT t.id, t.tx_date::date AS report_date, t.product_id, t.customer_id, t.qty, t.unit_cost, t.shipment_id, t.product_name_snapshot, t.product_spec_snapshot FROM public.inventory_transactions t WHERE t.tx_type = 'out' AND t.deleted_at IS NULL AND t.tx_date::date >= v_min_date AND t.tx_date::date <= v_max_date ), eff_tx AS ( SELECT b.id, b.report_date, b.product_id, b.customer_id, b.shipment_id, b.qty AS eff_qty, COALESCE(b.unit_cost, p.unit_price) AS eff_price, (b.unit_cost IS NULL AND p.unit_price IS NULL) AS missing_price, b.product_name_snapshot, b.product_spec_snapshot FROM base_out b LEFT JOIN public.products p ON p.id = b.product_id UNION ALL SELECT a.id, b.report_date, b.product_id, b.customer_id, b.shipment_id, CASE WHEN a.tx_type = 'adjust_in' THEN a.qty ELSE -a.qty END AS eff_qty, COALESCE(a.unit_cost, b.unit_cost, p.unit_price) AS eff_price, (a.unit_cost IS NULL AND b.unit_cost IS NULL AND p.unit_price IS NULL) AS missing_price, COALESCE(a.product_name_snapshot, b.product_name_snapshot) AS product_name_snapshot, COALESCE(a.product_spec_snapshot, b.product_spec_snapshot) AS product_spec_snapshot FROM public.inventory_transactions a JOIN base_out b ON b.id = a.adjusted_from_transaction_id LEFT JOIN public.products p ON p.id = b.product_id WHERE a.tx_type IN ('adjust_in', 'adjust_out') AND a.deleted_at IS NULL ), calc_tx AS ( SELECT *, eff_qty * COALESCE(eff_price, 0) AS revenue FROM eff_tx ), cust_dim AS ( SELECT ct.*, COALESCE(c.parent_customer_id, c.id, v_zero) AS parent_id, COALESCE(ap.code, c.code, 'CHUA_GAN_KHACH') AS parent_code, COALESCE(ap.name, c.name, 'Chua gan khach hang') AS parent_name, COALESCE(ap.selling_entity_id, c.selling_entity_id) AS selling_entity_id FROM calc_tx ct LEFT JOIN public.customers c ON c.id = ct.customer_id LEFT JOIN public.customers ap ON ap.id = COALESCE(c.parent_customer_id, c.id) ), cust_agg AS ( SELECT parent_id, parent_code, parent_name, selling_entity_id, COALESCE(SUM(revenue) FILTER (WHERE report_date >= p1_start AND report_date <= p1_end), 0) AS p1_revenue, COALESCE(SUM(revenue) FILTER (WHERE report_date >= p2_start AND report_date <= p2_end), 0) AS p2_revenue FROM cust_dim GROUP BY parent_id, parent_code, parent_name, selling_entity_id ) SELECT COALESCE(jsonb_agg(d), '[]'::jsonb) INTO v_customer_stats FROM ( SELECT parent_id::text AS id, parent_code AS code, parent_name AS name, selling_entity_id, p1_revenue, p2_revenue FROM cust_agg WHERE p1_revenue <> 0 OR p2_revenue <> 0 ORDER BY p1_revenue DESC, parent_code ASC ) d; WITH base_out AS ( SELECT t.id, t.tx_date::date AS report_date, t.product_id, t.customer_id, t.qty, t.unit_cost, t.shipment_id, t.product_name_snapshot, t.product_spec_snapshot FROM public.inventory_transactions t WHERE t.tx_type = 'out' AND t.deleted_at IS NULL AND t.tx_date::date >= v_min_date AND t.tx_date::date <= v_max_date ), eff_tx AS ( SELECT b.id, b.report_date, b.product_id, b.customer_id, b.shipment_id, b.qty AS eff_qty, COALESCE(b.unit_cost, p.unit_price) AS eff_price, (b.unit_cost IS NULL AND p.unit_price IS NULL) AS missing_price, b.product_name_snapshot, b.product_spec_snapshot FROM base_out b LEFT JOIN public.products p ON p.id = b.product_id UNION ALL SELECT a.id, b.report_date, b.product_id, b.customer_id, b.shipment_id, CASE WHEN a.tx_type = 'adjust_in' THEN a.qty ELSE -a.qty END AS eff_qty, COALESCE(a.unit_cost, b.unit_cost, p.unit_price) AS eff_price, (a.unit_cost IS NULL AND b.unit_cost IS NULL AND p.unit_price IS NULL) AS missing_price, COALESCE(a.product_name_snapshot, b.product_name_snapshot) AS product_name_snapshot, COALESCE(a.product_spec_snapshot, b.product_spec_snapshot) AS product_spec_snapshot FROM public.inventory_transactions a JOIN base_out b ON b.id = a.adjusted_from_transaction_id LEFT JOIN public.products p ON p.id = b.product_id WHERE a.tx_type IN ('adjust_in', 'adjust_out') AND a.deleted_at IS NULL ), calc_tx AS ( SELECT *, eff_qty * COALESCE(eff_price, 0) AS revenue FROM eff_tx ), prod_agg AS ( SELECT product_id, COALESCE(SUM(revenue) FILTER (WHERE report_date >= p1_start AND report_date <= p1_end), 0) AS p1_revenue, COALESCE(SUM(revenue) FILTER (WHERE report_date >= p2_start AND report_date <= p2_end), 0) AS p2_revenue, COALESCE(SUM(eff_qty) FILTER (WHERE report_date >= p1_start AND report_date <= p1_end), 0) AS p1_qty, COALESCE(SUM(eff_qty) FILTER (WHERE report_date >= p2_start AND report_date <= p2_end), 0) AS p2_qty, COALESCE(COUNT(*) FILTER (WHERE missing_price AND report_date >= p1_start AND report_date <= p1_end), 0)::int AS p1_missing_price_rows FROM calc_tx GROUP BY product_id ) SELECT COALESCE(jsonb_agg(d), '[]'::jsonb) INTO v_product_stats FROM ( SELECT COALESCE(pa.product_id, v_zero)::text AS id, COALESCE(p.sku, 'CHUA_GAN_MA') AS sku, COALESCE(p.name, 'Chua gan ma hang') AS name, pa.p1_revenue, pa.p2_revenue, pa.p1_qty, pa.p2_qty, pa.p1_missing_price_rows FROM prod_agg pa LEFT JOIN public.products p ON p.id = pa.product_id WHERE pa.p1_revenue <> 0 OR pa.p2_revenue <> 0 OR pa.p1_qty <> 0 OR pa.p2_qty <> 0 ORDER BY pa.p1_revenue DESC LIMIT 200 ) d; WITH base_out AS ( SELECT t.id, t.tx_date::date AS report_date, t.product_id, t.customer_id, t.qty, t.unit_cost, t.shipment_id, t.product_name_snapshot, t.product_spec_snapshot FROM public.inventory_transactions t WHERE t.tx_type = 'out' AND t.deleted_at IS NULL AND t.tx_date::date >= v_min_date AND t.tx_date::date <= v_max_date ), eff_tx AS ( SELECT b.id, b.report_date, b.product_id, b.customer_id, b.shipment_id, b.qty AS eff_qty, COALESCE(b.unit_cost, p.unit_price) AS eff_price, (b.unit_cost IS NULL AND p.unit_price IS NULL) AS missing_price, b.product_name_snapshot, b.product_spec_snapshot FROM base_out b LEFT JOIN public.products p ON p.id = b.product_id UNION ALL SELECT a.id, b.report_date, b.product_id, b.customer_id, b.shipment_id, CASE WHEN a.tx_type = 'adjust_in' THEN a.qty ELSE -a.qty END AS eff_qty, COALESCE(a.unit_cost, b.unit_cost, p.unit_price) AS eff_price, (a.unit_cost IS NULL AND b.unit_cost IS NULL AND p.unit_price IS NULL) AS missing_price, COALESCE(a.product_name_snapshot, b.product_name_snapshot) AS product_name_snapshot, COALESCE(a.product_spec_snapshot, b.product_spec_snapshot) AS product_spec_snapshot FROM public.inventory_transactions a JOIN base_out b ON b.id = a.adjusted_from_transaction_id LEFT JOIN public.products p ON p.id = b.product_id WHERE a.tx_type IN ('adjust_in', 'adjust_out') AND a.deleted_at IS NULL ), calc_tx AS ( SELECT *, eff_qty * COALESCE(eff_price, 0) AS revenue FROM eff_tx ), ent_dim AS ( SELECT ct.*, COALESCE(ap.selling_entity_id, c.selling_entity_id, v_zero) AS entity_id FROM calc_tx ct LEFT JOIN public.customers c ON c.id = ct.customer_id LEFT JOIN public.customers ap ON ap.id = COALESCE(c.parent_customer_id, c.id) ), ent_agg AS ( SELECT entity_id, COALESCE(SUM(revenue) FILTER (WHERE report_date >= p1_start AND report_date <= p1_end), 0) AS p1_revenue, COALESCE(SUM(revenue) FILTER (WHERE report_date >= p2_start AND report_date <= p2_end), 0) AS p2_revenue FROM ent_dim GROUP BY entity_id ) SELECT COALESCE(jsonb_agg(d), '[]'::jsonb) INTO v_entity_stats FROM ( SELECT ea.entity_id::text AS id, COALESCE(se.code, 'CHUA_GAN_PHAP_NHAN') AS code, COALESCE(se.header_text, 'Chua gan phap nhan') AS header_text, ea.p1_revenue, ea.p2_revenue FROM ent_agg ea LEFT JOIN public.selling_entities se ON se.id = ea.entity_id WHERE ea.p1_revenue <> 0 OR ea.p2_revenue <> 0 ORDER BY ea.p1_revenue DESC ) d; SELECT jsonb_build_object('p1_revenue', (var_kpis_json->>'p1_revenue')::numeric, 'customer_p1_revenue', COALESCE((SELECT SUM((x->>'p1_revenue')::numeric) FROM jsonb_array_elements(v_customer_stats) x), 0), 'product_p1_revenue', COALESCE((SELECT SUM((x->>'p1_revenue')::numeric) FROM jsonb_array_elements(v_product_stats) x), 0), 'entity_p1_revenue', COALESCE((SELECT SUM((x->>'p1_revenue')::numeric) FROM jsonb_array_elements(v_entity_stats) x), 0), 'missing_price_rows', (var_kpis_json->>'p1_missing_price_rows')::int) INTO v_diagnostics; RETURN jsonb_build_object('kpis', var_kpis_json, 'customer_report', v_customer_stats, 'product_report', v_product_stats, 'entity_report', v_entity_stats, 'diagnostics', v_diagnostics, 'generated_at', now() AT TIME ZONE 'Asia/Ho_Chi_Minh'); END; $$; GRANT EXECUTE ON FUNCTION public.sales_command_center_report_v2(date, date, date, date) TO authenticated; NOTIFY pgrst, 'reload schema'; COMMIT;
